param([string]$ResultArtifactFile="")
$ErrorActionPreference="Stop";$repoRoot=Split-Path -Parent $PSScriptRoot;$results=@()
function Add($c,$k,$s,$d){$script:results+=[ordered]@{category=$c;check=$k;status=$s;detail=$d};Write-Host ("{0}: {1} / {2} - {3}" -f $s,$c,$k,$d)}
function Resolve-LocalPath([string]$p){if([string]::IsNullOrWhiteSpace($p)){return $p};if([IO.Path]::IsPathRooted($p)){$p}else{Join-Path $repoRoot $p}}
function Hits($paths,$patterns){$e=@($paths|?{Test-Path $_});if(!$e){return @()};@(Select-String -Path $e -Pattern $patterns -SimpleMatch -ErrorAction SilentlyContinue)}
Write-Host "LMAX Read-Only Runtime Phase 6W GBPUSD Snapshot Result Gate"
Write-Host "Local-only by default. This gate does not connect to LMAX, request snapshots, replay, or use credentials."
foreach($i in @(@{n="GBPUSD result model";p="src/QQ.Production.Intraday.Infrastructure.Lmax/LmaxReadOnlyGbpusdManualSnapshotResult.cs"},@{n="GBPUSD wrapper script";p="scripts/run-lmax-readonly-runtime-demo-gbpusd-snapshot-once.ps1"},@{n="Phase 6W tests";p="tests/QQ.Production.Intraday.Tests.Unit/LmaxReadOnlyGbpusdManualSnapshotResultTests.cs"})){ $p=Join-Path $repoRoot $i.p;if(Test-Path $p){Add "Files" "$($i.n) exists" "PASS" $p}else{Add "Files" "$($i.n) exists" "FAIL" "Missing $p"}}
if([string]::IsNullOrWhiteSpace($ResultArtifactFile)){Add "Result" "Result artifact supplied" "WARN" "No result artifact supplied."}else{$p=Resolve-LocalPath $ResultArtifactFile;if(Test-Path $p){$t=Get-Content -Raw $p;$r=$t|ConvertFrom-Json;$scanText=$t -replace "LMAX_DEMO_FIX_PASSWORD","" -replace "passwordPresent","" -replace "passwordLength","" -replace "LMAX_DEMO_FIX_USERNAME","";if($scanText -match '(?i)(password\s*[:=]|secret\s*[:=]|token\s*[:=]|apikey\s*[:=]|api_key\s*[:=]|privatekey\s*[:=]|private_key\s*[:=]|authorization\s*[:=]|bearer\s+|\b553=|\b554=|host\s*=|user\s*=|account\s*=)'){Add "Result" "No sensitive content" "FAIL" "Sensitive-shaped content found."}else{Add "Result" "No sensitive content" "PASS" "No credential-shaped content."};if(([string]$r.symbol -eq "GBPUSD" -or [string]$r.instrument -eq "GBPUSD") -and [string]$r.securityId -eq "4002" -and [string]$r.securityIdSource -eq "8" -and -not[bool]$r.orderSubmissionAttempted -and -not[bool]$r.shadowReplaySubmitAttempted -and -not[bool]$r.tradingMutationAttempted -and -not[bool]$r.schedulerStarted -and -not[bool]$r.credentialValuesReturned -and [bool]$r.noSensitiveContent){Add "Result" "GBPUSD result safe" "PASS" "Result is sanitized and non-mutating."}else{Add "Result" "GBPUSD result safe" "FAIL" "Unsafe or mismatched result artifact."}}else{Add "Result" "Result artifact exists" "FAIL" "Missing $p"}}
$api=Join-Path $repoRoot "src/QQ.Production.Intraday.Api/Program.cs";$worker=Join-Path $repoRoot "src/QQ.Production.Intraday.Worker/Program.cs";$aw=@($api,$worker)
$reg=Hits $aw @("RealLmaxGateway","ExternalReadOnlyPrototypeGateway","LmaxVenueGatewaySkeleton","SecurityListRequest")
if($reg.Count-eq 0 -and (Select-String -Path $api -Pattern "FakeLmaxGateway" -SimpleMatch -Quiet)){Add "Registration" "API/Worker remain FakeLmaxGateway only" "PASS" "No real gateway registration found."}else{Add "Registration" "API/Worker remain FakeLmaxGateway only" "FAIL" (($reg|%{"$($_.Path):$($_.LineNumber)"})-join"; ")}
foreach($scan in @(@{c="Scheduler";k="No scheduler/polling added";p=@("PeriodicTimer","System.Threading.Timer","SecurityListPoll")},@{c="Replay";k="Runtime does not submit to shadow replay";p=@("SubmitToShadowReplay = true","SubmittedToShadowReplay = true","ReplaySubmitAsync")},@{c="Orders";k="No order surface";p=@("NewOrderSingle","OrderCancelRequest","OrderCancelReplaceRequest","SubmitOrder")},@{c="Mutation";k="No trading-state mutation references";p=@("PersistTrade","TradingState")})){ $h=Hits $aw $scan.p;if($h.Count-eq 0){Add $scan.c $scan.k "PASS" "No marker found in API/Worker startup."}else{Add $scan.c $scan.k "FAIL" (($h|%{"$($_.Path):$($_.LineNumber)"})-join"; ")}}
Add "Runtime" "External LMAX connection" "PASS" "This gate does not connect to LMAX.";Add "Snapshot" "MarketData snapshot" "PASS" "This gate does not request snapshots.";Add "Replay" "Manual replay" "PASS" "This gate does not replay evidence.";Add "Credentials" "Credential values" "PASS" "This gate does not require or print credential values."
$failed=@($results|? status -eq "FAIL");$warn=@($results|? status -eq "WARN");$decision=if($failed){"FAIL"}elseif($warn){"PASS_WITH_KNOWN_WARNINGS"}else{"PASS"}
$dir=Join-Path $repoRoot "artifacts/readiness";New-Item -ItemType Directory -Path $dir -Force|Out-Null;$path=Join-Path $dir "phase6w-gbpusd-snapshot-result-gate.json"
[ordered]@{generatedAtUtc=[DateTimeOffset]::UtcNow.ToString("o");finalDecision=$decision;phase="6W";orderSubmissionAttempted=$false;shadowReplaySubmitAttempted=$false;tradingMutationAttempted=$false;schedulerStarted=$false;results=$results}|ConvertTo-Json -Depth 10|Set-Content -LiteralPath $path -Encoding UTF8
Write-Host "";Write-Host "FinalDecision: $decision";Write-Host "Report: $path";if($decision-eq"FAIL"){exit 1}
